const INK = "#16130F";
const PANEL = "#1E1A14";
const BORDER = "#2E2820";
const GRID = "#2A251C";
const TEXT = "#EDE6D8";
const TEXT_2 = "#A89F8C";
const TEXT_3 = "#6E6656";
const GOLD = "#B5871D";
const GOLD_BRIGHT = "#E0A82E";
const TEAL = "#2FA084";

const fmtM = (n) => (n >= 1e9 ? `US$${(n / 1e9).toFixed(2)}B` : `US$${Math.round(n / 1e6)}M`);
const CONF_LABEL = { high: "dato duro", medium: "verificar", low: "señal" };

function useStats() {
  return useMemo(() => {
    const total = DATA.reduce((s, r) => s + (r.amount_usd || 0), 0);
    const byCountry = {};
    for (const r of DATA) {
      const c = r.country || "Sin país";
      byCountry[c] ??= { country: c, rondas: 0, capital: 0 };
      byCountry[c].rondas += 1;
      byCountry[c].capital += r.amount_usd || 0;
    }
    const countries = Object.values(byCountry).sort((a, b) => b.capital - a.capital);
    const divergencia = countries.slice(0, 8).map((c) => ({
      country: c.country,
      "% del capital": +((c.capital / total) * 100).toFixed(1),
      "% de las rondas": +((c.rondas / DATA.length) * 100).toFixed(1),
    }));
    const byMonth = {};
    for (const r of DATA) {
      const m = (r.date || "").slice(0, 7);
      if (m.length === 7) byMonth[m] = (byMonth[m] || 0) + (r.amount_usd || 0);
    }
    const mensual = Object.entries(byMonth).sort()
      .map(([mes, capital]) => ({ mes, "capital (US$M)": Math.round(capital / 1e6) }));
    const lastRun = DATA.reduce((m, r) => (r.first_seen_date > m ? r.first_seen_date : m), "");
    const senales = DATA.filter((r) => r.signal === "expansion" && r.first_seen_date === lastRun);
    return { total, divergencia, mensual, senales, lastRun };
  }, []);
}

const tooltipStyle = {
  contentStyle: { background: PANEL, border: `1px solid ${BORDER}`, borderRadius: 8, fontFamily: "'Space Mono', monospace", fontSize: 12 },
  labelStyle: { color: TEXT },
  itemStyle: { color: TEXT_2 },
};

function Section({ title, children }) {
  return (
    <section style={{ marginTop: 48 }}>
      <h2 style={{ fontFamily: "'Instrument Serif', serif", fontWeight: 400, fontSize: 28, color: TEXT, margin: "0 0 16px" }}>{title}</h2>
      {children}
    </section>
  );
}

export default function ExploradorCapitalLatam() {
  const { total, divergencia, mensual, senales, lastRun } = useStats();
  const [pais, setPais] = useState("todos");
  const [ronda, setRonda] = useState("todas");
  const paises = useMemo(() => [...new Set(DATA.map((r) => r.country).filter(Boolean))].sort(), []);
  const rondas = useMemo(() => [...new Set(DATA.map((r) => r.round_type).filter(Boolean))].sort(), []);
  const filtradas = DATA.filter((r) =>
    (pais === "todos" || r.country === pais) && (ronda === "todas" || r.round_type === ronda),
  ).sort((a, b) => (b.date || "").localeCompare(a.date || ""));

  const selectStyle = {
    background: PANEL, color: TEXT, border: `1px solid ${BORDER}`, borderRadius: 8,
    padding: "8px 12px", fontFamily: "'Space Grotesk', sans-serif", fontSize: 14,
  };

  return (
    <div style={{ minHeight: "100vh", background: INK, color: TEXT, fontFamily: "'Space Grotesk', sans-serif", padding: "48px 24px" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Instrument+Serif&family=Space+Grotesk:wght@400;500&family=Space+Mono&display=swap');
        table { border-collapse: collapse; width: 100%; }
        th, td { text-align: left; padding: 10px 12px; border-bottom: 1px solid ${BORDER}; font-size: 13px; }
        th { color: ${TEXT_3}; font-weight: 500; text-transform: uppercase; letter-spacing: 0.06em; font-size: 11px; }
        td.num { font-family: 'Space Mono', monospace; font-variant-numeric: tabular-nums; }
      `}</style>

      <div style={{ maxWidth: 960, margin: "0 auto" }}>
        <header>
          <p style={{ color: TEXT_2, fontSize: 14, margin: 0 }}>Radar de rondas LATAM · actualizado {lastRun}</p>
          <h1 style={{ fontFamily: "'Instrument Serif', serif", fontWeight: 400, fontSize: 64, margin: "8px 0 0", color: GOLD_BRIGHT }}>
            {fmtM(total)}
          </h1>
          <p style={{ color: TEXT_2, fontSize: 16, maxWidth: 560, lineHeight: 1.5 }}>
            en {DATA.length} rondas de inversión rastreadas. Solo montos disclosed; los totales mezclan equity, deuda y grants.
          </p>
        </header>

        <Section title="Quién pone la plata y quién pone las rondas">
          <ResponsiveContainer width="100%" height={320}>
            <BarChart data={divergencia} layout="vertical" barGap={2} margin={{ left: 24 }}>
              <CartesianGrid horizontal={false} stroke={GRID} />
              <XAxis type="number" unit="%" tick={{ fill: TEXT_3, fontSize: 12 }} stroke={BORDER} />
              <YAxis type="category" dataKey="country" width={90} tick={{ fill: TEXT_2, fontSize: 13 }} stroke={BORDER} />
              <Tooltip {...tooltipStyle} cursor={{ fill: "#ffffff10" }} />
              <Legend wrapperStyle={{ color: TEXT_2, fontSize: 13 }} />
              <Bar dataKey="% del capital" fill={GOLD} radius={[0, 4, 4, 0]} barSize={10} />
              <Bar dataKey="% de las rondas" fill={TEAL} radius={[0, 4, 4, 0]} barSize={10} />
            </BarChart>
          </ResponsiveContainer>
        </Section>

        <Section title="Capital por mes">
          <ResponsiveContainer width="100%" height={240}>
            <LineChart data={mensual}>
              <CartesianGrid vertical={false} stroke={GRID} />
              <XAxis dataKey="mes" tick={{ fill: TEXT_3, fontSize: 12 }} stroke={BORDER} />
              <YAxis tick={{ fill: TEXT_3, fontSize: 12 }} stroke={BORDER} />
              <Tooltip {...tooltipStyle} />
              <Line type="monotone" dataKey="capital (US$M)" stroke={GOLD} strokeWidth={2} dot={false} activeDot={{ r: 5 }} />
            </LineChart>
          </ResponsiveContainer>
        </Section>

        <Section title="Señales de esta semana">
          {senales.length === 0 ? (
            <p style={{ color: TEXT_2 }}>Sin señales de expansión nuevas en la última corrida.</p>
          ) : (
            <div style={{ display: "grid", gap: 12 }}>
              {senales.map((r) => (
                <div key={r.company + r.date} style={{ background: PANEL, border: `1px solid ${BORDER}`, borderRadius: 12, padding: "14px 18px", display: "flex", justifyContent: "space-between", alignItems: "baseline", flexWrap: "wrap", gap: 8 }}>
                  <div>
                    <strong style={{ fontSize: 16 }}>{r.company}</strong>
                    <span style={{ color: TEXT_2, marginLeft: 10, fontSize: 13 }}>
                      {r.country} · {r.round_type}{r.linkedin_person ? ` · anunció ${r.linkedin_person}` : ""}
                    </span>
                  </div>
                  <span style={{ fontFamily: "'Space Mono', monospace", color: GOLD_BRIGHT }}>
                    {r.amount_usd ? fmtM(r.amount_usd) : "monto no disclosed"}
                  </span>
                </div>
              ))}
            </div>
          )}
        </Section>

        <Section title={`Las ${DATA.length} rondas`}>
          <div style={{ display: "flex", gap: 12, marginBottom: 16 }}>
            <select value={pais} onChange={(e) => setPais(e.target.value)} style={selectStyle} aria-label="Filtrar por país">
              <option value="todos">Todos los países</option>
              {paises.map((p) => <option key={p} value={p}>{p}</option>)}
            </select>
            <select value={ronda} onChange={(e) => setRonda(e.target.value)} style={selectStyle} aria-label="Filtrar por tipo de ronda">
              <option value="todas">Todas las rondas</option>
              {rondas.map((r) => <option key={r} value={r}>{r}</option>)}
            </select>
          </div>
          <div style={{ overflowX: "auto", maxHeight: 480, overflowY: "auto" }}>
            <table>
              <thead>
                <tr><th>Empresa</th><th>País</th><th>Ronda</th><th>Monto</th><th>Fecha</th><th>Fuente</th></tr>
              </thead>
              <tbody>
                {filtradas.map((r) => (
                  <tr key={r.company + r.date + r.round_type}>
                    <td>{r.company}</td>
                    <td style={{ color: TEXT_2 }}>{r.country}</td>
                    <td style={{ color: TEXT_2 }}>{r.round_type}</td>
                    <td className="num">{r.amount_usd ? fmtM(r.amount_usd) : "—"}</td>
                    <td className="num" style={{ color: TEXT_2 }}>{r.date}</td>
                    <td>
                      <span style={{ fontSize: 11, border: `1px solid ${BORDER}`, borderRadius: 999, padding: "2px 8px", color: r.confidence === "high" ? TEAL : TEXT_2 }}>
                        {CONF_LABEL[r.confidence] || r.confidence}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <p style={{ color: TEXT_3, fontSize: 12, marginTop: 16, lineHeight: 1.6 }}>
            Fuentes: LatamList, LatAm Tech Weekly, latamfintech.co, Brazil Journal, NeoFeed, Finsiders.
            Cobertura de trackers y prensa, no censo del mercado. Conversiones BRL a USD aproximadas a la tasa del día de corrida. El mes en curso está parcial.
          </p>
        </Section>
      </div>
    </div>
  );
}
